import { render, screen, waitFor } from "@testing-library/react";
import userEvent from "@testing-library/user-event";
import { describe, expect, it } from "vitest";
import {
  Dialog,
  DialogClose,
  DialogContent,
  DialogDescription,
  DialogTitle,
  DialogTrigger,
} from "./Dialog";

function DialogExample() {
  return (
    <Dialog>
      <DialogTrigger>Open dialog</DialogTrigger>
      <DialogContent>
        <DialogTitle>Edit project</DialogTitle>
        <DialogDescription>Update the project settings.</DialogDescription>
        <button type="button">First action</button>
        <DialogClose>Done</DialogClose>
      </DialogContent>
    </Dialog>
  );
}

function CustomAriaDialogExample() {
  return (
    <Dialog>
      <DialogTrigger>Open fallback dialog</DialogTrigger>
      <DialogContent
        aria-describedby="archive-description"
        aria-labelledby="archive-title"
      >
        <h2 id="archive-title">Archive project</h2>
        <p id="archive-description">This can be restored later.</p>
        <DialogClose>Keep project</DialogClose>
      </DialogContent>
    </Dialog>
  );
}

function CustomSlotIdDialogExample() {
  return (
    <Dialog>
      <DialogTrigger>Open custom id dialog</DialogTrigger>
      <DialogContent>
        <DialogTitle id="custom-dialog-title">Custom title</DialogTitle>
        <DialogDescription id="custom-dialog-description">
          Custom description.
        </DialogDescription>
        <DialogClose>Close custom dialog</DialogClose>
      </DialogContent>
    </Dialog>
  );
}

describe("Dialog", () => {
  it("opens as a labelled modal, traps focus, and returns focus on Escape", async () => {
    const user = userEvent.setup();

    render(<DialogExample />);

    const trigger = screen.getByRole("button", { name: "Open dialog" });
    await user.click(trigger);

    const dialog = await screen.findByRole("dialog", {
      name: "Edit project",
    });
    const title = screen.getByText("Edit project");
    const description = screen.getByText("Update the project settings.");

    expect(dialog).toHaveAttribute("aria-modal", "true");
    expect(dialog).toHaveAccessibleName("Edit project");
    expect(dialog).toHaveAccessibleDescription("Update the project settings.");
    expect(dialog).toHaveAttribute("aria-labelledby", title.id);
    expect(dialog).toHaveAttribute("aria-describedby", description.id);
    expect(
      screen.getByRole("button", { name: "Close dialog" }),
    ).toBeInTheDocument();

    await waitFor(() => {
      expect(screen.getByRole("button", { name: "First action" })).toHaveFocus();
    });

    await user.tab();
    expect(screen.getByRole("button", { name: "Done" })).toHaveFocus();

    await user.tab();
    expect(screen.getByRole("button", { name: "First action" })).toHaveFocus();

    await user.tab({ shift: true });
    expect(screen.getByRole("button", { name: "Done" })).toHaveFocus();

    await user.keyboard("{Escape}");
    expect(screen.queryByRole("dialog")).not.toBeInTheDocument();
    expect(trigger).toHaveFocus();
  });

  it("uses explicit ARIA labels when title and description slots are absent", async () => {
    const user = userEvent.setup();

    render(<CustomAriaDialogExample />);

    const trigger = screen.getByRole("button", {
      name: "Open fallback dialog",
    });
    await user.click(trigger);

    const dialog = await screen.findByRole("dialog", {
      name: "Archive project",
    });

    expect(dialog).toHaveAttribute("aria-labelledby", "archive-title");
    expect(dialog).toHaveAttribute("aria-describedby", "archive-description");
    expect(dialog).toHaveAccessibleDescription("This can be restored later.");

    await user.click(screen.getByRole("button", { name: "Close dialog" }));

    expect(screen.queryByRole("dialog")).not.toBeInTheDocument();
    expect(trigger).toHaveFocus();
  });

  it("uses custom title and description ids from slots", async () => {
    const user = userEvent.setup();

    render(<CustomSlotIdDialogExample />);

    await user.click(
      screen.getByRole("button", { name: "Open custom id dialog" }),
    );

    const dialog = await screen.findByRole("dialog", {
      name: "Custom title",
    });

    expect(dialog).toHaveAttribute("aria-labelledby", "custom-dialog-title");
    expect(dialog).toHaveAttribute(
      "aria-describedby",
      "custom-dialog-description",
    );
    expect(dialog).toHaveAccessibleDescription("Custom description.");
  });
});

"use client";

export { Dialog } from "./DialogContext";
export type { DialogProps } from "./DialogContext";
export { DialogClose } from "./DialogClose";
export type { DialogCloseProps } from "./DialogClose";
export { DialogContent } from "./DialogContent";
export type { DialogContentProps } from "./DialogContent";
export {
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from "./DialogSections";
export type {
  DialogDescriptionProps,
  DialogFooterProps,
  DialogHeaderProps,
  DialogTitleProps,
} from "./DialogSections";
export { DialogTrigger } from "./DialogTrigger";
export type { DialogTriggerProps } from "./DialogTrigger";
export type { DialogSize, DialogTone, DialogVariant } from "./dialog-types";

"use client";

import type { ButtonHTMLAttributes } from "react";
import { forwardRef } from "react";
import {
  Slot,
  cn,
  disabledInteractiveStyles,
  focusVisibleStyles,
  swirskiAttrs,
} from "../../system";
import { useDialog } from "./DialogContext";
import type { DialogSize, DialogTone, DialogVariant } from "./dialog-types";
import { dialogButtonSizeStyles } from "./dialog-utils";

export type DialogCloseProps = ButtonHTMLAttributes<HTMLButtonElement> & {
  asChild?: boolean;
  variant?: DialogVariant;
  size?: DialogSize;
  tone?: DialogTone;
};

export const DialogClose = forwardRef<HTMLButtonElement, DialogCloseProps>(
  function DialogClose(
    {
      asChild = false,
      className,
      children = "Close",
      variant = "default",
      size = "md",
      tone = "default",
      onClick,
      ...props
    },
    ref,
  ) {
    const { setOpen } = useDialog();
    const Component = asChild ? Slot : "button";

    return (
      <Component
        ref={ref}
        className={cn(
          "border-[length:var(--sw-border-width)] border-[color:var(--sw-color-ink)] bg-[var(--sw-color-surface)] font-black uppercase shadow-[4px_4px_0_var(--sw-color-shadow)] outline-none transition-all duration-150 hover:translate-x-1 hover:translate-y-1 hover:shadow-none active:translate-x-2 active:translate-y-2 disabled:hover:shadow-[4px_4px_0_var(--sw-color-shadow)]",
          focusVisibleStyles,
          disabledInteractiveStyles,
          dialogButtonSizeStyles[size],
          className,
        )}
        onClick={(event) => {
          onClick?.(event);

          if (!event.defaultPrevented) {
            setOpen(false);
          }
        }}
        type={asChild ? undefined : "button"}
        {...swirskiAttrs("dialog-close", { size, tone, variant })}
        {...props}
      >
        {children}
      </Component>
    );
  },
);

DialogClose.displayName = "DialogClose";

"use client";

import type { HTMLAttributes } from "react";
import { forwardRef, useRef } from "react";
import { createPortal } from "react-dom";
import { cn, composeRefs, swirskiAttrs } from "../../system";
import { useModalOverlay } from "../../system/overlay";
import { usePortalRoot } from "../../hooks/use-portal-root/usePortalRoot";
import { useDialog } from "./DialogContext";
import type { DialogSize, DialogTone, DialogVariant } from "./dialog-types";
import { dialogContentSizeStyles } from "./dialog-utils";

export type DialogContentProps = {
  variant?: DialogVariant;
  size?: DialogSize;
  tone?: DialogTone;
} & HTMLAttributes<HTMLDivElement>;

export const DialogContent = forwardRef<HTMLDivElement, DialogContentProps>(
  function DialogContent(
    {
      className,
      children,
      variant = "default",
      size = "md",
      tone = "default",
      ...props
    },
    ref,
  ) {
    const { describedById, labelledById, open, setOpen } = useDialog();
    const portalRoot = usePortalRoot();
    const contentRef = useRef<HTMLDivElement>(null);

    useModalOverlay({
      contentRef,
      onEscape: () => setOpen(false),
      open,
    });

    if (!open || !portalRoot) {
      return null;
    }

    return createPortal(
      <div className="fixed inset-0 z-50 grid place-items-center bg-black/45 p-4">
        <button
          aria-label="Close dialog"
          className="absolute inset-0"
          onClick={() => setOpen(false)}
          type="button"
        />
        <div
          ref={composeRefs(contentRef, ref)}
          className={cn(
            "relative z-10 w-full border-4 border-black bg-white shadow-[12px_12px_0_#0B0B0C]",
            dialogContentSizeStyles[size],
            variant === "compact" && "shadow-[8px_8px_0_#0B0B0C]",
            className,
          )}
          role="dialog"
          aria-modal="true"
          aria-labelledby={labelledById ?? props["aria-labelledby"]}
          aria-describedby={describedById ?? props["aria-describedby"]}
          tabIndex={-1}
          {...swirskiAttrs("dialog-content", { size, tone, variant })}
          {...props}
        >
          {children}
        </div>
      </div>,
      portalRoot,
    );
  },
);

DialogContent.displayName = "DialogContent";

"use client";

import type { ReactNode } from "react";
import { createContext, useCallback, useContext, useId, useState } from "react";
import type { DialogSize, DialogTone, DialogVariant } from "./dialog-types";

type DialogContextValue = {
  open: boolean;
  setOpen: (open: boolean) => void;
  titleId: string;
  descriptionId: string;
  labelledById?: string;
  describedById?: string;
  setLabelledById: (id: string | undefined) => void;
  setDescribedById: (id: string | undefined) => void;
};

export const DialogContext = createContext<DialogContextValue | null>(null);

export type DialogProps = {
  children: ReactNode;
  open?: boolean;
  defaultOpen?: boolean;
  onOpenChange?: (open: boolean) => void;
  variant?: DialogVariant;
  size?: DialogSize;
  tone?: DialogTone;
};

export function useDialog() {
  const context = useContext(DialogContext);

  if (!context) {
    throw new Error("Dialog components must be used inside Dialog.");
  }

  return context;
}

export function Dialog({
  children,
  open,
  defaultOpen = false,
  onOpenChange,
  variant: _variant = "default",
  size: _size = "md",
  tone: _tone = "default",
}: DialogProps) {
  const titleId = useId();
  const descriptionId = useId();
  const [internalOpen, setInternalOpen] = useState(defaultOpen);
  const [labelledById, setLabelledById] = useState<string | undefined>();
  const [describedById, setDescribedById] = useState<string | undefined>();
  const isControlled = open !== undefined;
  const currentOpen = open ?? internalOpen;

  const setOpen = useCallback((nextOpen: boolean) => {
    if (!isControlled) {
      setInternalOpen(nextOpen);
    }

    onOpenChange?.(nextOpen);
  }, [isControlled, onOpenChange]);

  return (
    <DialogContext.Provider
      value={{
        open: currentOpen,
        setOpen,
        titleId,
        descriptionId,
        labelledById,
        describedById,
        setLabelledById,
        setDescribedById,
      }}
    >
      {children}
    </DialogContext.Provider>
  );
}

"use client";

import type { HTMLAttributes } from "react";
import { forwardRef, useEffect } from "react";
import { Slot, cn, swirskiAttrs } from "../../system";
import { useDialog } from "./DialogContext";
import type { DialogSize, DialogTone, DialogVariant } from "./dialog-types";

export type DialogHeaderProps = {
  asChild?: boolean;
  variant?: DialogVariant;
  size?: DialogSize;
  tone?: DialogTone;
} & HTMLAttributes<HTMLDivElement>;

export const DialogHeader = forwardRef<HTMLDivElement, DialogHeaderProps>(
  function DialogHeader(
    {
      asChild = false,
      className,
      variant = "default",
      size = "md",
      tone = "default",
      ...props
    },
    ref,
  ) {
    const Component = asChild ? Slot : "div";

    return (
      <Component
        ref={ref}
        className={cn("grid gap-2", className)}
        {...swirskiAttrs("dialog-header", { size, tone, variant })}
        {...props}
      />
    );
  },
);

DialogHeader.displayName = "DialogHeader";

export type DialogTitleProps = {
  asChild?: boolean;
  variant?: DialogVariant;
  size?: DialogSize;
  tone?: DialogTone;
} & HTMLAttributes<HTMLHeadingElement>;

export const DialogTitle = forwardRef<HTMLHeadingElement, DialogTitleProps>(
  function DialogTitle(
    {
      asChild = false,
      className,
      variant = "default",
      size = "md",
      tone = "default",
      ...props
    },
    ref,
  ) {
    const { setLabelledById, titleId } = useDialog();
    const Component = asChild ? Slot : "h2";
    const id = props.id ?? titleId;

    useEffect(() => {
      setLabelledById(id);
      return () => setLabelledById(undefined);
    }, [id, setLabelledById]);

    return (
      <Component
        ref={ref}
        className={cn("font-anton text-4xl uppercase leading-none", className)}
        id={id}
        {...swirskiAttrs("dialog-title", { size, tone, variant })}
        {...props}
      />
    );
  },
);

DialogTitle.displayName = "DialogTitle";

export type DialogDescriptionProps = {
  asChild?: boolean;
  variant?: DialogVariant;
  size?: DialogSize;
  tone?: DialogTone;
} & HTMLAttributes<HTMLParagraphElement>;

export const DialogDescription = forwardRef<
  HTMLParagraphElement,
  DialogDescriptionProps
>(function DialogDescription(
  {
    asChild = false,
    className,
    variant = "default",
    size = "md",
    tone = "default",
    ...props
  },
  ref,
) {
  const { descriptionId, setDescribedById } = useDialog();
  const Component = asChild ? Slot : "p";
  const id = props.id ?? descriptionId;

  useEffect(() => {
    setDescribedById(id);
    return () => setDescribedById(undefined);
  }, [id, setDescribedById]);

  return (
    <Component
      ref={ref}
      className={cn("text-sm font-bold leading-6 text-black/65", className)}
      id={id}
      {...swirskiAttrs("dialog-description", { size, tone, variant })}
      {...props}
    />
  );
});

DialogDescription.displayName = "DialogDescription";

export type DialogFooterProps = {
  asChild?: boolean;
  variant?: DialogVariant;
  size?: DialogSize;
  tone?: DialogTone;
} & HTMLAttributes<HTMLDivElement>;

export const DialogFooter = forwardRef<HTMLDivElement, DialogFooterProps>(
  function DialogFooter(
    {
      asChild = false,
      className,
      variant = "default",
      size = "md",
      tone = "default",
      ...props
    },
    ref,
  ) {
    const Component = asChild ? Slot : "div";

    return (
      <Component
        ref={ref}
        className={cn("mt-6 flex flex-wrap justify-end gap-3", className)}
        {...swirskiAttrs("dialog-footer", { size, tone, variant })}
        {...props}
      />
    );
  },
);

DialogFooter.displayName = "DialogFooter";

"use client";

import type { ButtonHTMLAttributes } from "react";
import { forwardRef } from "react";
import {
  Slot,
  cn,
  disabledInteractiveStyles,
  focusVisibleStyles,
  swirskiAttrs,
} from "../../system";
import { useDialog } from "./DialogContext";
import type { DialogSize, DialogTone, DialogVariant } from "./dialog-types";
import { dialogButtonSizeStyles } from "./dialog-utils";

export type DialogTriggerProps = ButtonHTMLAttributes<HTMLButtonElement> & {
  asChild?: boolean;
  variant?: DialogVariant;
  size?: DialogSize;
  tone?: DialogTone;
};

export const DialogTrigger = forwardRef<HTMLButtonElement, DialogTriggerProps>(
  function DialogTrigger(
    {
      asChild = false,
      className,
      children,
      variant = "default",
      size = "md",
      tone = "default",
      onClick,
      ...props
    },
    ref,
  ) {
    const { setOpen } = useDialog();
    const Component = asChild ? Slot : "button";

    return (
      <Component
        ref={ref}
        className={cn(
          "inline-flex border-[length:var(--sw-border-width)] border-[color:var(--sw-color-ink)] bg-[var(--sw-color-blue)] font-black uppercase text-white shadow-[5px_5px_0_var(--sw-color-shadow)] outline-none transition-all duration-150 hover:translate-x-1 hover:translate-y-1 hover:shadow-none active:translate-x-2 active:translate-y-2 disabled:hover:shadow-[5px_5px_0_var(--sw-color-shadow)]",
          focusVisibleStyles,
          disabledInteractiveStyles,
          dialogButtonSizeStyles[size],
          variant === "compact" && "shadow-[3px_3px_0_var(--sw-color-shadow)] disabled:hover:shadow-[3px_3px_0_var(--sw-color-shadow)]",
          className,
        )}
        onClick={(event) => {
          onClick?.(event);

          if (!event.defaultPrevented) {
            setOpen(true);
          }
        }}
        type={asChild ? undefined : "button"}
        {...swirskiAttrs("dialog-trigger", { size, tone, variant })}
        {...props}
      >
        {children}
      </Component>
    );
  },
);

DialogTrigger.displayName = "DialogTrigger";

export type DialogVariant = "default" | "compact";
export type DialogSize = "sm" | "md" | "lg";
export type DialogTone = "default";

import type { DialogSize } from "./dialog-types";

export const dialogButtonSizeStyles: Record<DialogSize, string> = {
  sm: "px-4 py-2 text-sm",
  md: "px-5 py-3",
  lg: "px-6 py-4 text-lg",
};

export const dialogContentSizeStyles: Record<DialogSize, string> = {
  sm: "max-w-md p-5",
  md: "max-w-lg p-6",
  lg: "max-w-2xl p-7",
};
